const items = $input.all();
const now = new Date().toISOString();

const masLogs = items[0]?.json?.logs || [];
const auditLogs = items[1]?.json?.entries || [];
const n8nErrors = items[2]?.json?.data || [];

const anomalies = [];

// Check for error bursts (>10 errors in 10 min window)
const errorCount = masLogs.filter(l => l.level === 'ERROR' || l.level === 'CRITICAL').length;
if (errorCount > 10) {
  anomalies.push({
    type: 'error_burst',
    severity: 'high',
    message: `${errorCount} errors in last 10 minutes`,
    details: masLogs.slice(0, 5).map(l => l.message || l.msg).join('; ')
  });
}

// Check for critical errors
const criticals = masLogs.filter(l => l.level === 'CRITICAL');
if (criticals.length > 0) {
  anomalies.push({
    type: 'critical_error',
    severity: 'critical',
    message: `${criticals.length} CRITICAL errors detected`,
    details: criticals.map(l => l.message || l.msg).join('; ')
  });
}

// Check for unusual audit patterns (>50 actions in 10 min)
if (auditLogs.length > 50) {
  anomalies.push({
    type: 'unusual_activity',
    severity: 'medium',
    message: `Unusual activity: ${auditLogs.length} audit entries in 10 minutes`,
    details: 'Possible automated attack or misconfigured service'
  });
}

// Check for repeated n8n failures
const failedWorkflows = {};
for (const exec of n8nErrors) {
  const name = exec.workflowName || exec.workflowId || 'unknown';
  failedWorkflows[name] = (failedWorkflows[name] || 0) + 1;
}
const repeatedFailures = Object.entries(failedWorkflows).filter(([_, count]) => count >= 3);
if (repeatedFailures.length > 0) {
  anomalies.push({
    type: 'workflow_failure_loop',
    severity: 'high',
    message: `Repeated workflow failures: ${repeatedFailures.map(([name, count]) => name + ' (' + count + 'x)').join(', ')}`,
    details: 'Workflows failing repeatedly may indicate systemic issues'
  });
}

// Check for auth failures in audit
const authFailures = auditLogs.filter(l => 
  (l.action || '').includes('auth_fail') || 
  (l.action || '').includes('unauthorized') ||
  (l.action || '').includes('forbidden')
);
if (authFailures.length >= 5) {
  anomalies.push({
    type: 'auth_anomaly',
    severity: 'high',
    message: `${authFailures.length} authentication failures detected`,
    details: 'Possible brute force or credential stuffing attempt'
  });
}

const report = {
  timestamp: now,
  log_counts: {
    mas_errors: errorCount,
    audit_entries: auditLogs.length,
    n8n_errors: n8nErrors.length
  },
  anomalies: anomalies,
  has_anomalies: anomalies.length > 0,
  max_severity: anomalies.reduce((max, a) => {
    const levels = { critical: 4, high: 3, medium: 2, low: 1 };
    return levels[a.severity] > levels[max] ? a.severity : max;
  }, 'low')
};

return [{ json: report }];
